244	              content="All inbound, outbound and traffic within the requested namespaces."
245	              entryDelay={1250}
246	              triggerRef={tooltipTotalRef}
247	            />
248	
249	            <Tab style={summaryFont} title="Inbound" eventKey={0} ref={tooltipInboundRef}>
