272	                    rate5xx={httpIn.rate5xx}
273	                    rateNR={httpIn.rateNoResponse}
274	                  />
275	                )}
276	
277	                {tcpIn.rate > 0 && <RateTableTcp rate={tcpIn.rate} />}
278	                {
279	                  // We don't show a sparkline here because we need to aggregate the traffic of an
