281	                }
282	              </div>
283	            </Tab>
284	            <Tab style={summaryFont} title="Outbound" eventKey={1} ref={tooltipOutboundRef}>
285	              <div style={summaryFont}>
286	                {grpcOut.rate === 0 && httpOut.rate === 0 && tcpOut.rate === 0 && (
287	                  <div className={noTrafficStyle}>
288	                    <KialiIcon.Info /> No outbound traffic.
289	                  </div>
290	                )}
291	
292	                {grpcOut.rate > 0 && (
293	                  <RateTableGrpc
294	                    isRequests={isGrpcRequests}
295	                    rate={grpcOut.rate}
296	                    rateGrpcErr={grpcOut.rateGrpcErr}
297	                    rateNR={grpcOut.rateNoResponse}
298	                  />
299	                )}
300	
301	                {httpOut.rate > 0 && (
302	                  <RateTableHttp
303	                    title="HTTP (requests per second):"
304	                    rate={httpOut.rate}
305	                    rate3xx={httpOut.rate3xx}
306	                    rate4xx={httpOut.rate4xx}
307	                    rate5xx={httpOut.rate5xx}
308	                    rateNR={httpOut.rateNoResponse}
