362	  private getGraphTraffic = (): SummaryPanelGraphTraffic => {
363	    const controller = this.props.data.summaryTarget as Visualization;
364	    const { nodes } = elems(controller);
365	
366	    // when getting total traffic rates don't count requests from injected service nodes
367	    const nonServiceNodes = select(nodes, { prop: NodeAttr.nodeType, val: NodeType.SERVICE, op: '!=' });
368	    const nonBoxNodes = select(nonServiceNodes, { prop: NodeAttr.isBox, op: 'falsy' });
369	    const totalEdges = edgesOut(nonBoxNodes as Node[]).length;
370	    const inboundEdges = edgesOut(select(nodes, { prop: NodeAttr.isRoot, op: 'truthy' }) as Node[]);
371	    const allLeafNodes = leafNodes(nodes) as Node[];
372	    const outboundEdges = edgesIn(
373	      _.union(
374	        select(allLeafNodes, { prop: NodeAttr.isOutside, op: 'truthy' }),
375	        select(allLeafNodes, { prop: NodeAttr.isServiceEntry, op: 'truthy' })
376	      ) as Node[]
377	    );
378	
379	    return {
380	      grpcIn: getAccumulatedTrafficRateGrpc(inboundEdges),
381	      grpcOut: getAccumulatedTrafficRateGrpc(outboundEdges),
382	      grpcTotal: getAccumulatedTrafficRateGrpc(totalEdges),
383	      httpIn: getAccumulatedTrafficRateHttp(inboundEdges),
384	      httpOut: getAccumulatedTrafficRateHttp(outboundEdges),
385	      httpTotal: getAccumulatedTrafficRateHttp(totalEdges),
386	      isGrpcRequests: this.props.trafficRates.includes(TrafficRate.GRPC_REQUEST),
387	      tcpIn: getAccumulatedTrafficRateTcp(inboundEdges),
388	      tcpOut: getAccumulatedTrafficRateTcp(outboundEdges),
389	      tcpTotal: getAccumulatedTrafficRateTcp(totalEdges)
390	    };
391	  };
