393	  private countApps = (): { numApps: number; numVersions: number } => {
394	    const controller = this.props.data.summaryTarget as Visualization;
395	    const { nodes } = elems(controller);
396	
397	    const appVersions: { [key: string]: Set<string> } = {};
398	
399	    select(nodes, { prop: NodeAttr.nodeType, val: NodeType.APP }).forEach(appNode => {
400	      const d = appNode.getData() as NodeData;
401	      const app = d[NodeAttr.app];
402	
403	      if (appVersions[app] === undefined) {
404	        appVersions[app] = new Set();
405	      }
406	
407	      appVersions[app].add(d[NodeAttr.version]);
408	    });
409	
410	    return {
411	      numApps: Object.getOwnPropertyNames(appVersions).length,
412	      numVersions: Object.getOwnPropertyNames(appVersions).reduce((totalCount: number, version: string) => {
413	        return totalCount + appVersions[version].size;
414	      }, 0)
415	    };
416	  };
