461	  private renderTopologySummary = (
462	    numSvc: number,
463	    numWorkloads: number,
464	    numApps: number,
465	    numVersions: number,
466	    numEdges: number
467	  ): React.ReactNode => (
468	    <>
469	      {numApps > 0 && (
