517	
518	    // When there is any traffic for the protocol, show both inbound and outbound charts. It's a little
519	    // confusing because for the tabs inbound is limited to just traffic entering the namespace, and outbound
520	    // is limited to just traffic exitingt the namespace.  But in the charts inbound ad outbound also
521	    // includes traffic within the namespace.
522	    const { grpcTotal, httpTotal, isGrpcRequests, tcpTotal } = this.graphTraffic!;
523	
524	    return (
525	      <>
526	        {grpcTotal.rate > 0 && isGrpcRequests && (
527	          <>
528	            <RequestChart
529	              label="gRPC - Inbound Request Traffic"
