535	              label="gRPC - Outbound Request Traffic"
536	              dataRps={this.state.grpcRequestOut}
537	              dataErrors={this.state.grpcRequestErrOut}
538	            />
539	          </>
540	        )}
541	
542	        {grpcTotal.rate > 0 && !isGrpcRequests && (
543	          <>
544	            <StreamChart
545	              label="gRPC - Inbound Traffic"
546	              receivedRates={this.state.grpcReceivedIn}
547	              sentRates={this.state.grpcSentIn}
548	              unit="messages"
549	            />
550	
551	            <StreamChart
552	              label="gRPC - Outbound Traffic"
553	              receivedRates={this.state.grpcReceivedOut}
554	              sentRates={this.state.grpcSentOut}
555	              unit="messages"
556	            />
557	          </>
558	        )}
