560	        {httpTotal.rate > 0 && (
561	          <>
562	            <RequestChart
563	              label="HTTP - Inbound Request Traffic"
564	              dataRps={this.state.httpRequestIn}
565	              dataErrors={this.state.httpRequestErrIn}
566	            />
567	
568	            <RequestChart
569	              label="HTTP - Outbound Request Traffic"
570	              dataRps={this.state.httpRequestOut}
571	              dataErrors={this.state.httpRequestErrOut}
572	            />
573	          </>
574	        )}
