576	        {tcpTotal.rate > 0 && (
577	          <>
578	            <StreamChart
579	              label="TCP - Inbound Traffic"
580	              receivedRates={this.state.tcpReceivedIn}
581	              sentRates={this.state.tcpSentIn}
582	              unit="bytes"
583	            />
584	
585	            <StreamChart
586	              label="TCP - Outbound Traffic"
587	              receivedRates={this.state.tcpReceivedOut}
