597	  private updateCharts = (): void => {
598	    const props: SummaryPanelPropType = this.props;
599	    const namespace = props.namespaces[0].name;
600	
601	    if (namespace === UNKNOWN) {
602	      this.setState({
603	        loading: false
604	      });
605	      return;
606	    }
607	
608	    // When there is any traffic for the protocol, show both inbound and outbound charts. It's a little
609	    // confusing because for the tabs inbound is limited to just traffic entering the namespace, and outbound
610	    // is limited to just traffic exitingt the namespace.  But in the charts inbound ad outbound also
611	    // includes traffic within the namespace.
612	    const { grpcTotal, httpTotal, isGrpcRequests, tcpTotal } = this.graphTraffic!;
613	
614	    if (this.metricsPromise) {
615	      this.metricsPromise.cancel();
616	      this.metricsPromise = undefined;
617	    }
618	
619	    let promiseIn: Promise<ApiResponse<IstioMetricsMap>> = Promise.resolve({ data: {} });
620	    let promiseOut: Promise<ApiResponse<IstioMetricsMap>> = Promise.resolve({ data: {} });
621	
622	    let filters: string[] = [];
623	
624	    if (grpcTotal.rate > 0 && !isGrpcRequests) {
625	      filters.push('grpc_sent', 'grpc_received');
626	    }
627	
628	    if (httpTotal.rate > 0 || (grpcTotal.rate > 0 && isGrpcRequests)) {
629	      filters.push('request_count', 'request_error_count');
630	    }
631	
632	    if (tcpTotal.rate > 0) {
633	      filters.push('tcp_sent', 'tcp_received');
634	    }
635	
636	    if (filters.length > 0) {
637	      promiseIn = API.getNamespaceMetrics(namespace, {
638	        byLabels: ['request_protocol'], // ignored by prom if it doesn't exist
639	        direction: 'inbound',
640	        duration: props.duration,
641	        includeAmbient: serverConfig.ambientEnabled,
642	        filters: filters,
643	        queryTime: props.queryTime,
644	        rateInterval: props.rateInterval,
645	        reporter: 'destination',
646	        step: props.step
647	      });
648	
649	      promiseOut = API.getNamespaceMetrics(namespace, {
650	        byLabels: ['request_protocol'], // ignored by prom if it doesn't exist
651	        direction: 'outbound',
652	        duration: props.duration,
653	        filters: filters,
654	        includeAmbient: serverConfig.ambientEnabled,
655	        queryTime: props.queryTime,
656	        rateInterval: props.rateInterval,
657	        reporter: 'source',
658	        step: props.step
659	      });
660	    }
661	
662	    this.metricsPromise = makeCancelablePromise(Promise.all([promiseIn, promiseOut]));
663	
664	    this.metricsPromise.promise
665	      .then(responses => {
666	        const comparator = (labels: Labels, protocol?: Protocol): boolean => {
667	          return protocol ? labels.request_protocol === protocol : true;
668	        };
669	
670	        const metricsIn = responses[0].data;
671	        const metricsOut = responses[1].data;
672	
673	        this.setState({
674	          loading: false,
675	          grpcReceivedIn: getFirstDatapoints(metricsIn.grpc_received),
676	          grpcReceivedOut: getFirstDatapoints(metricsOut.grpc_received),
677	          grpcRequestIn: getDatapoints(metricsIn.request_count, comparator, Protocol.GRPC),
678	          grpcRequestOut: getDatapoints(metricsOut.request_count, comparator, Protocol.GRPC),
679	          grpcRequestErrIn: getDatapoints(metricsIn.request_error_count, comparator, Protocol.GRPC),
680	          grpcRequestErrOut: getDatapoints(metricsOut.request_error_count, comparator, Protocol.GRPC),
681	          grpcSentIn: getFirstDatapoints(metricsIn.grpc_sent),
682	          grpcSentOut: getFirstDatapoints(metricsOut.grpc_sent),
683	          httpRequestIn: getDatapoints(metricsIn.request_count, comparator, Protocol.HTTP),
684	          httpRequestOut: getDatapoints(metricsOut.request_count, comparator, Protocol.HTTP),
685	          httpRequestErrIn: getDatapoints(metricsIn.request_error_count, comparator, Protocol.HTTP),
686	          httpRequestErrOut: getDatapoints(metricsOut.request_error_count, comparator, Protocol.HTTP),
687	          tcpReceivedIn: getFirstDatapoints(metricsIn.tcp_received),
688	          tcpReceivedOut: getFirstDatapoints(metricsOut.tcp_received),
689	          tcpSentIn: getFirstDatapoints(metricsIn.tcp_sent),
690	          tcpSentOut: getFirstDatapoints(metricsOut.tcp_sent)
691	        });
692	      })
693	      .catch(error => {
694	        if (error.isCanceled) {
695	          console.debug('SummaryPanelGraph: Ignore fetch error (canceled).');
696	          return;
697	        }
698	
699	        const errorMsg = error.response && error.response.data.error ? error.response.data.error : error.message;
700	
701	        this.setState({
702	          loading: false,
703	          metricsLoadError: errorMsg,
704	          ...defaultMetricsState
705	        });
706	      });
707	
708	    this.setState({ loading: true, metricsLoadError: null });
709	  };
