711	  private updateValidations = (): void => {
712	    const promises = Object.keys(serverConfig.clusters).map(cluster =>
713	      API.getConfigValidations(
714	        namespacesForCluster(this.props.namespaces, store.getState().namespaces.items, cluster).join(','),
715	        cluster
716	      )
717	    );
718	    this.validationSummaryPromises
719	      .registerAll('validationSummary', promises)
720	      .then(responses => {
721	        const validationsMap = new Map<string, ValidationStatus>();
722	        responses.forEach((response: ApiResponse<ValidationStatus[]>) => {
723	          response.data.forEach(validationSummary => {
724	            // Merge validations across clusters for the same namespace.
725	            if (!validationSummary.namespace) {
726	              return;
727	            }
728	
729	            const currentValidation = validationsMap.get(validationSummary.namespace);
730	            if (currentValidation) {
731	              validationSummary.errors += currentValidation.errors;
732	              validationSummary.warnings += currentValidation.warnings;
733	              if (currentValidation.objectCount !== undefined && validationSummary.objectCount !== undefined) {
734	                validationSummary.objectCount += currentValidation.objectCount;
735	              } else if (validationSummary.objectCount !== undefined) {
736	                validationSummary.objectCount = currentValidation.objectCount;
737	              }
738	            }
739	
740	            validationsMap.set(validationSummary.namespace, validationSummary);
741	          });
742	        });
743	        this.setState({ validationsMap });
744	      })
745	
746	      .catch(err => {
747	        if (!err.isCanceled) {
748	          console.info(`SummaryPanelGraph: Error fetching validation status: ${API.getErrorString(err)}`);
749	        }
750	      });
751	  };
